using NP std;
NP phigrOS
{
    il ll read()
    {
        ll x=0,f=1;char ch=gc();
        wh(ch<'0'||ch>'9'){if(ch=='-')f=-1;ch=getchar();}
        wh(ch>='0'&&ch<='9'){x=x*10+ch-'0';ch=gc();}
        return x*f;
    }
    void write(ll x)
    {
        if(x<0)pc('-'),x=-x;
        if(x>9)write(x/10);
        pc(x%10+'0');
    }
    void writeln(ll x)
    {
        write(x);
        puts("");
        return;
    }
}
using NP phigrOS;
double l,c,k,m,a[55],b[55],an=inf;
int n;
void f(int u,double p,double s)
{
	if(s>=an)return;
	if(u>n)
	{
		an=s;
		return;
	}
	double d=a[u+1]-a[u];
	if(p<c/2||p*k<d)
		f(u+1,c-d/k,s+(c-p)*b[u]+20);
	if(p*k>=d)
		f(u+1,p-d/k,s);
}
signed main(void)
{
	cin>>l>>c>>k>>m>>n;
	FOR(i,1,n)cin>>a[i]>>b[i];
	a[n+1]=l;
	f(1,c-a[1]/k,m);
	printf("%.1f",an);
	return false;
}
